"use client";

import { useEffect, useRef } from "react";
import { motion } from "framer-motion";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/dist/ScrollTrigger";
import { ArrowUpRight, Palette, Cpu, Zap, Globe } from "lucide-react";

gsap.registerPlugin(ScrollTrigger);

const luxuryExpertise = [
    {
        title: "Flexible & Precise Manufacturing",
        description: "We turn designs into high-quality products by blending advanced technology with craftsmanship. Combining industrial precision and handcrafted detail across wood, metal, crystal, leather, 3D printing, and more. Our flexible manufacturing delivers customized solutions with consistent quality and accuracy.",
        image: "https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?q=80&w=2070&auto=format&fit=crop",
        icon: <Palette className="w-6 h-6" />,
        features: [
            "Powered by ten integrated production lines.",
            "Flexible, multi-material manufacturing techniques.",
            "Large-scale gifting and printing operations.",
            "Managing small to large production runs."
        ]
    },
    {
        title: "Communication Solutions & Events",
        description: "We turn gifts and interactive experiences into effective communication tools within campaigns and events. We design and execute integrated experiences that connect design, message, and occasion into one cohesive story.",
        image: "https://images.unsplash.com/photo-1513519245088-0e12902e5a38?q=80&w=2070&auto=format&fit=crop",
        icon: <Globe className="w-6 h-6" />,
        features: [
            "Designing and managing seasonal events at scale.",
            "Developing interactive event gifts and experiences.",
            "Cultural and national occasion solutions.",
            "Consulting on gifts for communication strategies."
        ]
    },
    {
        title: "Digital Ecosystems & AI",
        description: "We develop intelligent digital platforms for national and cultural occasions. Our AI-driven solutions enhance user engagement and provide seamless interactive experiences across all touchpoints, ensuring your message resonates in the digital age.",
        image: "https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=2072&auto=format&fit=crop",
        icon: <Zap className="w-6 h-6" />,
        features: [
            "AI-powered interactive storytelling.",
            "High-end web and mobile applications.",
            "Scalable back-end infrastructure for massive events.",
            "Data-driven design and audience analytics."
        ]
    }
];

export default function HorizontalGallery() {
    const sectionRef = useRef<HTMLElement>(null);
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (!sectionRef.current || !containerRef.current) return;

        let ctx = gsap.context(() => {
            if (!containerRef.current) return;
            const horizontalLength = containerRef.current.scrollWidth - window.innerWidth;

            gsap.to(containerRef.current, {
                x: -horizontalLength,
                ease: "none",
                scrollTrigger: {
                    trigger: sectionRef.current,
                    pin: true,
                    scrub: 1,
                    end: () => "+=" + horizontalLength,
                    invalidateOnRefresh: true,
                },
            });
        }, sectionRef);

        return () => ctx.revert();
    }, []);

    return (
        <section id="expertise" ref={sectionRef} className="relative min-h-screen bg-transparent overflow-hidden">
            <div className="absolute top-24 left-10 md:left-24 z-20">
                <h2 className="text-sm tracking-[0.4em] uppercase text-primary mb-4">Our Expertise</h2>
                <h3 className="text-5xl md:text-8xl font-light luxury-text italic">The Art of <span className="font-bold not-italic">Creation</span></h3>
            </div>

            <div
                ref={containerRef}
                className="flex gap-12 px-10 md:px-24 h-screen items-center"
                style={{ width: "fit-content" }}
            >
                {luxuryExpertise.map((project, index) => (
                    <div
                        key={index}
                        className="w-[90vw] md:w-[85vw] h-[80vh] flex-shrink-0 relative group"
                    >
                        <div className="w-full h-full green-3d-gradient backdrop-blur-xl rounded-[60px] overflow-hidden border border-white/10 flex flex-col md:flex-row transition-all duration-700 group-hover:border-primary/30">
                            {/* Image Section */}
                            <div className="w-full md:w-1/2 h-2/5 md:h-full relative overflow-hidden p-8 md:p-12">
                                <div className="w-full h-full rounded-[40px] overflow-hidden relative shadow-2xl">
                                    <img
                                        src={project.image}
                                        alt={project.title}
                                        className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110"
                                    />
                                    <div className="absolute inset-0 bg-gradient-to-t from-[#0b0d09]/60 to-transparent"></div>
                                </div>
                            </div>

                            {/* Text Section */}
                            <div className="w-full md:w-1/2 h-3/5 md:h-full p-10 md:p-20 flex flex-col justify-center">
                                <div className="flex items-center gap-6 mb-12">
                                    <div className="w-16 h-16 rounded-full border border-white/10 flex items-center justify-center group-hover:bg-primary group-hover:text-black transition-all duration-700 shadow-[0_0_20px_rgba(204,255,0,0.1)]">
                                        {project.icon}
                                    </div>
                                    <h4 className="text-3xl md:text-5xl font-bold luxury-text leading-tight">{project.title}</h4>
                                </div>

                                <p className="text-lg md:text-xl text-text-secondary leading-relaxed mb-12 font-light">
                                    {project.description}
                                </p>

                                <ul className="space-y-6 mb-12">
                                    {project.features.map((feature, idx) => (
                                        <li key={idx} className="flex items-start gap-4 text-sm md:text-md font-medium tracking-wide">
                                            <div className="w-2 h-2 rounded-full bg-primary mt-1.5 flex-shrink-0 gold-glow"></div>
                                            <span className="opacity-70">{feature}</span>
                                        </li>
                                    ))}
                                </ul>

                                <div className="mt-auto">
                                    <button className="flex items-center gap-3 text-[10px] font-bold tracking-[0.4em] uppercase text-white/40 hover:text-primary transition-colors group/btn">
                                        Explore Deeply <ArrowUpRight className="w-5 h-5 group-hover/btn:translate-x-1 group-hover/btn:-translate-y-1 transition-transform" />
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </section>
    );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

// Sound synthesizer using Web Audio API
const playSound = (index: number) => {
    const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContext) return;

    const ctx = new AudioContext();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    const frequencies = [261.63, 293.66, 329.63, 349.23, 392.00, 440.00, 493.88, 523.25];
    osc.frequency.setValueAtTime(frequencies[index % frequencies.length], ctx.currentTime);
    osc.type = index % 4 === 0 ? "square" : index % 4 === 1 ? "sawtooth" : index % 4 === 2 ? "triangle" : "sine";

    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + 0.5);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.5);
};

export default function InteractiveLab() {
    const [visuals, setVisuals] = useState<{ id: number; type: string; x: number; y: number; color: string }[]>([]);
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            const index = e.keyCode;
            playSound(index);

            const newVisual = {
                id: Date.now(),
                type: ["circle", "burst", "wave", "rect"][index % 4],
                x: Math.random() * window.innerWidth,
                y: Math.random() * window.innerHeight,
                color: index % 2 === 0 ? "#8B5CF6" : "#EC4899"
            };

            setVisuals((prev) => [...prev, newVisual]);
            setTimeout(() => {
                setVisuals((prev) => prev.filter((v) => v.id !== newVisual.id));
            }, 1000);
        };

        window.addEventListener("keydown", handleKeyDown);
        return () => {
            window.removeEventListener("keydown", handleKeyDown);
        };
    }, []);

    return (
        <div ref={containerRef} className="fixed inset-0 pointer-events-none z-[50] overflow-hidden">
            {/* Patatap Visuals */}
            <AnimatePresence>
                {visuals.map((v) => (
                    <motion.div
                        key={v.id}
                        initial={{ scale: 0, opacity: 1 }}
                        animate={{ scale: 4, opacity: 0 }}
                        exit={{ opacity: 0 }}
                        className="absolute rounded-full border-2 border-primary"
                        style={{
                            left: v.x,
                            top: v.y,
                            width: 100,
                            height: 100,
                            marginLeft: -50,
                            marginTop: -50,
                            borderColor: v.color,
                            borderRadius: v.type === "rect" ? "0%" : "50%"
                        }}
                    />
                ))}
            </AnimatePresence>
        </div>
    );
}

"use client";

import React, { useRef, useMemo, useEffect } from "react";
import { useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
// @ts-ignore
import { GPUComputationRenderer } from "three/examples/jsm/misc/GPUComputationRenderer";

const PARTICLE_WIDTH = 128; // Increased density
const PARTICLE_COUNT = PARTICLE_WIDTH * PARTICLE_WIDTH;

const simulationVertexShader = `
  void main() {
    gl_Position = vec4(position, 1.0);
  }
`;

const fragmentShaderPosition = `
  void main() {
    vec2 uv = gl_FragCoord.xy / resolution.xy;
    vec4 pos = texture2D(texturePosition, uv);
    vec4 vel = texture2D(textureVelocity, uv);
    
    pos.xyz += vel.xyz * 0.016; // Simple integration
    
    gl_FragColor = pos;
  }
`;

const fragmentShaderVelocity = `
  uniform float uTime;
  uniform vec2 uMouse;
  uniform float uInfluence;
  
  // Simplex 2D noise
  vec3 permute(vec3 x) { return mod(((x*34.0)+1.0)*x, 289.0); }
  float snoise(vec2 v){
    const vec4 C = vec4(0.211324865405187, 0.366025403784439, -0.577350269189626, 0.024390243902439);
    vec2 i  = floor(v + dot(v, C.yy) );
    vec2 x0 = v -   i + dot(i, C.xx);
    vec2 i1;
    i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec4 x12 = x0.xyxy + C.xxzz;
    x12.xy -= i1;
    i = mod(i, 289.0);
    vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 )) + i.x + vec3(0.0, i1.x, 1.0 ));
    vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
    m = m*m ; m = m*m ;
    vec3 x = 2.0 * fract(p * C.www) - 1.0;
    vec3 h = abs(x) - 0.5;
    vec3 a0 = x - floor(x + 0.5);
    vec3 g = a0 * vec3(x0.x,x12.x,x12.z) + h * vec3(x0.y,x12.y,x12.w);
    float n = 130.0 * dot(m, g);
    return n;
  }

  void main() {
    vec2 uv = gl_FragCoord.xy / resolution.xy;
    vec4 pos = texture2D(texturePosition, uv);
    vec4 vel = texture2D(textureVelocity, uv);
    
    vec3 force = vec3(0.0);
    
    // 1. Fluid Flow (Noise)
    float noise = snoise(pos.xy * 0.1 + uTime * 0.2);
    force.x += cos(noise * 6.28) * 0.5;
    force.y += sin(noise * 6.28) * 0.5;
    
    // 2. Cursor Interaction (Liquid Displacement)
    vec2 mouse = uMouse;
    float dist = distance(pos.xy, mouse);
    float radius = 4.0;
    if(dist < radius) {
        vec2 dir = normalize(pos.xy - mouse);
        float power = (1.0 - dist / radius) * 15.0;
        force.xy += dir * power;
    }
    
    // 3. Return to Center/Tether (Liquid Surface Tension)
    vec2 center = vec2(0.0); // Assuming spawn around center
    // force.xy -= (pos.xy - center) * 0.01;
    
    vel.xyz += force * 0.1;
    vel.xyz *= 0.95; // Damping
    
    gl_FragColor = vel;
  }
`;

const particleVertexShader = `
  uniform sampler2D texturePosition;
  uniform float uPixelRatio;
  varying float vLife;

  void main() {
    vec4 pos = texture2D(texturePosition, uv);
    vec4 mvPosition = modelViewMatrix * vec4(pos.xyz, 1.0);
    
    gl_PointSize = (10.0 * uPixelRatio) / -mvPosition.z;
    gl_Position = projectionMatrix * mvPosition;
    vLife = 1.0; 
  }
`;

const particleFragmentShader = `
  varying float vLife;
  void main() {
    float r = distance(gl_PointCoord, vec2(0.5));
    if (r > 0.5) discard;
    
    float glow = exp(-r * 4.0);
    vec3 color = vec3(0.8, 1.0, 0.0); // Neon Green
    gl_FragColor = vec4(color, glow * vLife * 0.4);
  }
`;

export default function LiquidParticles() {
  const { gl, size, viewport } = useThree();
  const pointsRef = useRef<THREE.Points>(null);
  const gpuRef = useRef<any>(null);
  const positionVariable = useRef<any>(null);
  const velocityVariable = useRef<any>(null);
  const mouseRef = useRef(new THREE.Vector2());

  const { gpu, posVar, velVar } = useMemo(() => {
    const gpu = new GPUComputationRenderer(PARTICLE_WIDTH, PARTICLE_WIDTH, gl);

    const dtPosition = gpu.createTexture();
    const dtVelocity = gpu.createTexture();

    const posData = dtPosition.image.data;
    const velData = dtVelocity.image.data;

    for (let i = 0; i < posData.length; i += 4) {
      // Use a deterministic-looking but pseudo-random approach or just suppress if we must
      // but for purity, let's just move the random generation outside the render loop if possible.
      // However, posData is a typed array.
      posData[i] = (Math.random() - 0.5) * 40;
      posData[i + 1] = (Math.random() - 0.5) * 40;
      posData[i + 2] = 0;
      posData[i + 3] = 1;

      velData[i] = 0;
      velData[i + 1] = 0;
      velData[i + 2] = 0;
      velData[i + 3] = 1;
    }

    const posVar = gpu.addVariable("texturePosition", fragmentShaderPosition, dtPosition);
    const velVar = gpu.addVariable("textureVelocity", fragmentShaderVelocity, dtVelocity);

    gpu.setVariableDependencies(posVar, [posVar, velVar]);
    gpu.setVariableDependencies(velVar, [posVar, velVar]);

    velVar.material.uniforms.uTime = { value: 0 };
    velVar.material.uniforms.uMouse = { value: new THREE.Vector2(0, 0) };

    const error = gpu.init();
    if (error !== null) console.error(error);

    return { gpu, posVar, velVar };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [gl]);

  useEffect(() => {
    gpuRef.current = gpu;
    positionVariable.current = posVar;
    velocityVariable.current = velVar;
  }, [gpu, posVar, velVar]);

  const geometry = useMemo(() => {
    const geo = new THREE.BufferGeometry();
    const positions = new Float32Array(PARTICLE_COUNT * 3);
    const uvs = new Float32Array(PARTICLE_COUNT * 2);

    for (let i = 0; i < PARTICLE_COUNT; i++) {
      const x = (i % PARTICLE_WIDTH) / PARTICLE_WIDTH;
      const y = Math.floor(i / PARTICLE_WIDTH) / PARTICLE_WIDTH;
      uvs[i * 2] = x;
      uvs[i * 2 + 1] = y;
    }

    geo.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    geo.setAttribute("uv", new THREE.BufferAttribute(uvs, 2));
    return geo;
  }, []);

  const material = useMemo(() => {
    return new THREE.ShaderMaterial({
      uniforms: {
        texturePosition: { value: null },
        uPixelRatio: { value: Math.min(window.devicePixelRatio, 2) }
      },
      vertexShader: particleVertexShader,
      fragmentShader: particleFragmentShader,
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false
    });
  }, []);

  useFrame((state) => {
    if (gpuRef.current) {
      velocityVariable.current.material.uniforms.uTime.value = state.clock.getElapsedTime();

      // Map state.mouse to world space
      mouseRef.current.set(
        (state.mouse.x * viewport.width) / 2,
        (state.mouse.y * viewport.height) / 2
      );
      velocityVariable.current.material.uniforms.uMouse.value.copy(mouseRef.current);

      gpuRef.current.compute();

      if (pointsRef.current) {
        (pointsRef.current.material as THREE.ShaderMaterial).uniforms.texturePosition.value =
          gpuRef.current.getCurrentRenderTarget(positionVariable.current).texture;
      }
    }
  });

  return (
    <points ref={pointsRef} geometry={geometry} material={material} />
  );
}

