                camera={{ position: [0, 0, 30], fov: 60 }}
                gl={{ antialias: true, alpha: true }}
            >
                <fog attach="fog" args={["#020202", 10, 60]} />
                <ParticleField />
            </Canvas>
        </div>
    );
}
